import{_ as e}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{o as i,c as o,a as r}from"./chunks/runtime-core.esm-bundler.BcSW7cUG.js";const u=JSON.parse('{"title":"Рефлексия","description":"","frontmatter":{"title":"Рефлексия","date":"2020-09-05T00:00:00.000Z","permalink":"/reflection","head":[["link",{"rel":"canonical","href":"https://alterfo.github.io/posts/2020-09-05-reflection"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"Рефлексия"}],["meta",{"property":"og:description","content":"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки."}],["meta",{"property":"og:url","content":"https://alterfo.github.io/posts/2020-09-05-reflection"}],["meta",{"property":"og:image","content":"https://alterfo.github.io/og.png"}],["meta",{"property":"og:site_name","content":"Alterfo"}],["meta",{"property":"og:locale","content":"ru_RU"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Рефлексия"}],["meta",{"name":"twitter:description","content":"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки."}],["meta",{"name":"twitter:image","content":"https://alterfo.github.io/og.png"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BlogPosting\\",\\"headline\\":\\"Рефлексия\\",\\"description\\":\\"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки.\\",\\"url\\":\\"https://alterfo.github.io/posts/2020-09-05-reflection\\",\\"inLanguage\\":\\"ru-RU\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Oleg Sidorkin\\",\\"alternateName\\":\\"alterfo\\",\\"url\\":\\"https://alterfo.github.io\\",\\"jobTitle\\":\\"Software Engineer\\",\\"knowsAbout\\":[\\"Music\\",\\"Audio DSP\\",\\"AI\\",\\"RAG\\",\\"Frontend Development\\",\\"Solution Architecture\\"],\\"sameAs\\":[\\"https://github.com/alterfo\\"]},\\"datePublished\\":\\"2020-09-05\\"}"]]},"headers":[],"relativePath":"posts/2020-09-05-reflection.md","filePath":"posts/2020-09-05-reflection.md"}'),l={name:"posts/2020-09-05-reflection.md"};function n(a,t,p,s,c,m){return i(),o("div",null,[...t[0]||(t[0]=[r('<blockquote><p>Reflect (verb): to prevent passage of and cause to change direction — <a href="https://www.merriam-webster.com/dictionary/reflect" target="_blank" rel="noreferrer">Marriam-Webster dictionary</a></p></blockquote><p>Умение смотреть назад, на самого себя и на содержание и функции своего сознания - наиважнейший навык в карьерном росте. Это называется рефлексией.</p><p>Анализируя своё прошлое, можно понять что на самом деле важно и каким образом формируются цели, решения, желания.</p><p>Если вам что-то на самом деле важно, вы действуете. Поэтому важно прояснить ценности чтобы принимать важные решения уверенно. Также, осознание своих ценностей даёт вам мощное ощущение собственной идентичности и уникальности.</p><p>Ценности познаются в сравнении. Ценность возникает при сравнении с чем-либо. Я могу сказать что мне важны деньги, но бывают ситуации, когда деньги уже не имеют такой ценности - при проблемах со здоровьем, с близкими. Это ставит деньги в иерархии ценностей чуть ниже чем здоровье и отношения.</p><p>Также, потребность в уважении может перевесить ценность отношений или денег.</p><p>Ценности требуют жертв. Чем-то приходится жертвовать в пользу того, что важно.</p><p>Возьмем за основу деньги. Но что значат деньги? Безопасность? Может быть, статус? Возможность путешествовать? То есть, деньги это важно, но ценность не в них самих, а в возможностях, которые они дают и как вы их используете.</p><p>Ценности меняются со временем, поэтому очень важно периодически пересматривать их для понимания куда двигаться дальше.</p><hr><p>Давайте проделаем простое упражнение</p><ol start="0"><li>Нарисуйте горизонтальную линию.</li><li>Определите временной промежуток для ревизии. Стартовой точкой может быть выпуск из университета, начало работы как специалиста. Важно чтобы можно было обнаружить повторяющиеся паттерны в принятии решений.</li><li>Определите периоды для ревизии. Это могут быть отчетные месяцы, или переходы между проектами или должностями.</li><li>Вспомните что вы делали на каждом этапе. Резюме или дневник могут помочь освежить память.</li><li>Нарисуйте вертикальную линию в точке старта и начертите кривую своего эмоционального состояния через все периоды.</li><li>Назовите эти эмоции и их противоположности, это могут быть: <ul><li>любопытство-скука</li><li>благодарность-сожаление</li><li>радость-печаль</li><li>принадлежность-изолированность</li><li>добавьте своих</li></ul></li><li>Подумайте что было важно для вас в то время. Какие потребности были удовлетворены или нет.</li><li>Ищите паттерны, ответьте на несколько вопросов: <ul><li>Были ли эмоции, которые повторялись снова и снова?</li><li>Были ли реакции, которые сложно объяснить?</li><li>Были ли ситуации когда вы что-то не хотели замечать, но это сильно сказалось потом?</li><li>На что вам следует обращать внимание в будущем чтобы ваши потребности были с большей вероятностью удовлетворены?</li></ul></li></ol>',12)])])}const d=e(l,[["render",n]]);export{u as __pageData,d as default};
